    #[test]
    fn test_single_paragraph() {
        let chunker = PdfChunker::new();
        let chunks = chunker.chunk("Just one paragraph.", &meta()).unwrap();
        assert_eq!(chunks.len(), 1);
    }

    #[test]
    fn test_empty_text() {
        let chunker = PdfChunker::new();
        let chunks = chunker.chunk("", &meta()).unwrap();
        assert!(chunks.is_empty());
    }

    #[test]
    fn test_chunk_type() {
        let chunker = PdfChunker::new();
        let chunks = chunker.chunk("Some PDF text.\n\nMore text.", &meta()).unwrap();
        assert!(!chunks.is_empty());
        assert_eq!(chunks[0].chunk_type, "paragraph");
    }

    #[test]
    fn test_name_and_extensions() {
        let chunker = PdfChunker::new();
        assert_eq!(chunker.name(), "pdf");
        assert_eq!(chunker.supported_extensions(), &["pdf"]);
    }
}
```

NOTE: The PdfChunker will receive pre-extracted text as `source`. The actual PDF byte reading + text extraction happens in the ingestion layer (IngestionAdapter reads the bytes and calls `pdf_extract::extract_text`). This keeps the `ChunkingStrategy` trait synchronous and pure-text.
